+    /// Show a new notification.
+    Show(Notification),
+    /// Dismiss a notification by ID.
+    Dismiss(u64),
+    /// Dismiss the oldest notification.
+    DismissOldest,
+    /// Clear all notifications.
+    ClearAll,
+}
+
